  ('colonel-7fec267e-moex-00136', 'colonel-7fec267e', 'colonel-7fec267e-moex-112-3082b5f1', 'sub-colonel-7fec267e-02', NULL, 'essay', 'X為某地方自治團體公有零售市場攤位使用人，Y為該地方自治團體
市公所。X 與 Y 簽訂公有市場零售攤位租賃契約，於該契約書中約
定如下：
㉑使用期間屆滿，X有優先承租權，但須於契約屆滿前 6 個月申請繼
續使用並簽訂契約，否則 X即須無條件將攤位交還與 Y。
㉒ X 應繳納使用費每月新臺幣 5,000 元。使用費之收費標準得由 Y
訂定及調整，並列舉調整原因通知 X繳納。逾期繳納者，每逾 2日
按所滯納金額之1%加徵滯納金，滯納金加徵金額不得超過應繳納
使用費之15%。
㉓市場若有下列情形之一者，Y 應於 3 個月前辦理公告，公告期間
屆滿後，X應於通知期限內無條件遷離市場，並停止繳納使用費：
⑴政策需要、⑵城鄉改造、⑶已無市場商業機能、⑷其他不可抗力
因素致無法繼續使用。
X 與 Y 簽訂上開攤位租賃契約後，於契約有效期間，Y 因政策需要
及都市計畫整體開發所需，乃辦理該契約中所約定之公告，並於公告
屆滿後函文通知 X 於契約期滿後不再續約。請依相關法規、司法實
務及主要學說分析：X與Y所簽訂之攤位租賃契約之法律性質為何？
Y 對 X 所作之函文通知，其法律性質為何？X 如對 Y 之函文通知不
服，應循何種程序進行救濟？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "145c21d5e0dd", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "301", "s": "0302", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
